// ==========================
// Leitura do input
// ==========================
const items = $input.all();

const data = items[0].json;

// ==========================
// Dados principais
// ==========================
const participanteNome = data.name;
const eventoNome = data.title;
const emailDestino = data.email;

// (exemplo fixo, mas pode vir do trigger se quiser adaptar)
const pergunta = $('Webhook').first().json.body.question

function formatarDataBR(isoDate) {
  if (!isoDate) return '';

  // Data em UTC
  const dateUTC = new Date(isoDate);

  // Ajuste manual para BRT (UTC-3)
  const offsetBrasil = -3 * 60; // minutos
  const dataBrasil = new Date(dateUTC.getTime() + offsetBrasil * 60 * 1000);

  const dia = String(dataBrasil.getDate()).padStart(2, '0');
  const mes = String(dataBrasil.getMonth() + 1).padStart(2, '0');
  const ano = dataBrasil.getFullYear();

  const hora = String(dataBrasil.getHours()).padStart(2, '0');
  const minuto = String(dataBrasil.getMinutes()).padStart(2, '0');

  return `${dia}/${mes}/${ano} às ${hora}:${minuto}`;
}

const askedAtISO = $('Webhook').first().json.body.asked_at
const dataPergunta = formatarDataBR(askedAtISO);

// ==========================
// Assunto do email
// ==========================
const subject = `Nova pergunta pendente no evento "${eventoNome}"`;

// ==========================
// Corpo HTML
// ==========================
const html = `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
</head>
<body style="margin:0;padding:0;background:#f6f7f9;font-family:Arial,Helvetica,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="padding:24px;">
    <tr>
      <td align="center">
        <table width="600" style="background:#ffffff;border-radius:8px;overflow:hidden;">

          <tr>
            <td style="background:#ff7a00;color:#fff;padding:20px;">
              <h2 style="margin:0;font-size:20px;">Nova pergunta pendente</h2>
            </td>
          </tr>

          <tr>
            <td style="padding:24px;">
              <p style="font-size:14px;color:#333;">
                Um participante enviou uma nova pergunta no evento <strong>${eventoNome}</strong>.
              </p>

              <table width="100%" style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:6px;margin:16px 0;">
                <tr>
                  <td style="padding:16px;">
                    <p style="margin:0 0 6px;font-size:13px;color:#6b7280;">
                      <strong>Participante:</strong> ${participanteNome}
                    </p>
                    <p style="margin:0 0 6px;font-size:13px;color:#6b7280;">
                      <strong>Data:</strong> ${dataPergunta}
                    </p>
                    <p style="margin-top:12px;font-size:14px;color:#111;">
                      <strong>Pergunta:</strong><br />
                      ${pergunta}
                    </p>
                  </td>
                </tr>
              </table>

              <a
                href="https://dagaz-core-portal.lovable.app/eventos/${data.id}?tab=pendentes"
                style="
                  display:inline-block;
                  padding:12px 20px;
                  background:#ff7a00;
                  color:#fff;
                  text-decoration:none;
                  border-radius:6px;
                  font-size:14px;
                  font-weight:bold;
                "
              >
                Responder pergunta
              </a>

              <p style="margin-top:24px;font-size:12px;color:#6b7280;">
                Você recebeu este e-mail porque é responsável pelo evento.
              </p>
            </td>
          </tr>

          <tr>
            <td style="background:#f3f4f6;padding:12px;text-align:center;font-size:12px;color:#6b7280;">
              © 2026 • Plataforma de Eventos Dagaz
            </td>
          </tr>

        </table>
      </td>
    </tr>
  </table>
</body>
</html>
`;

// ==========================
// Retorno para o n8n
// ==========================
return [
  {
    json: {
      to: emailDestino,
      subject,
      html
    }
  }
];

const emails = items[0].json.notification_email.split(',');

return emails.map(email => ({
  json: { 
    ...items[0].json,
    email: email.trim()
  }
}));

